var PluginModule=(()=>{(function(){let i="https://store.externulls.com";async function c(a){try{let e=await http_get(i+"/api/video/random"),s=JSON.parse(e.body),t=[];for(let o of s.data.slice(0,20))t.push(new MultimediaItem({title:o.title||"No title",url:String(o.id),posterUrl:o.preview_url||o.thumbnail||""}));a({success:!0,data:{Featured:t}})}catch(e){a({success:!1,errorCode:"HOME_ERROR",message:e.toString()})}}async function l(a,e){try{let s=await http_get(i+"/api/video/search/"+encodeURIComponent(a)),t=JSON.parse(s.body),o=[];for(let r of t.data)o.push(new MultimediaItem({title:r.title||"No title",url:String(r.id),posterUrl:r.preview_url||r.thumbnail||""}));e({success:!0,data:o})}catch(s){e({success:!1,errorCode:"SEARCH_ERROR",message:s.toString()})}}async function n(a,e){try{let s=await http_get(i+"/api/video/"+a),t=JSON.parse(s.body).data,o=new MultimediaItem({title:t.title||"No title",url:a,description:t.description||"",posterUrl:t.preview_url||t.thumbnail||"",episodes:[new Episode({name:"Video",url:t.hls_resources?.fl_cdn_720||t.hls_resources?.fl_cdn_480||t.file})]});e({success:!0,data:o})}catch(s){e({success:!1,errorCode:"LOAD_ERROR",message:s.toString()})}}async function d(a,e){try{e({success:!0,data:[new StreamResult({url:a,quality:720,source:"Beeg"})]})}catch(s){e({success:!1,errorCode:"STREAM_ERROR",message:s.toString()})}}globalThis.getHome=c,globalThis.search=l,globalThis.load=n,globalThis.loadStreams=d})();})();
Object.assign(globalThis, PluginModule);
